require"UI.UIBase"require"UI.UIBlock"UI_Disconnect=UIBase:Inherit()local a=GameUtility.EConnectState;local b=Basic.Enum({'closed','gotoShow','showing','gotoClose'})function UI_Disconnect:OnCreate()UI_Disconnect.Inst=self;self.timerMgr=TimerMgr:Init()self.showState=b.closed;self.count=0;self.locking=false end;function UI_Disconnect:OnShow(c)if self.showState==b.gotoShow or self.showState==b.showing then return end;LogTool.Debug('UI_Disconnect','Show')self.showState=b.gotoShow;self.timerMgr:ClearAllTimers()self.timerMgr:Delay(2,function()if self.showState==b.gotoShow then self.transform.gameObject:SetActive(true)self.showState=b.showing;self.locking=true;self:AnimPopOut(self.root,function()self.locking=false;c()end)end end)self:_refreshInfo()self.timerMgr:Loop(0.5,-1,function()self:_refreshInfo()end)end;function UI_Disconnect:OnClose(c)LogTool.Debug('UI_Disconnect','Hide')self.timerMgr:ClearAllTimers()self.showState=b.gotoClose;self.locking=true;self:AnimPopHide(self.root,function()if self.showState==b.gotoClose then self.locking=false;self.transform.gameObject:SetActive(false)self.showState=b.closed;c()end end)end;function UI_Disconnect:_refreshInfo()self.count=(self.count+1)%4;local d=''for e=1,self.count do d=d..'.'end;local f=LobbyNetMgr.GetConnectState()if f==a.closed or f==a.closing or f==a.none then self.desc.text=Tools.StrOfLocalization(2049)self.dot.text=''elseif f==a.reconnecting or f==a.connecting then self.desc.text=Tools.StrOfLocalization(2050)self.dot.text=d elseif f==a.usable then if Scene_MJ.Inst:is_in_mj()and not MJNetMgr.Inst.net.closed then local g=MJNetMgr.Inst:GetConnectState()if g==a.none or g==a.tryconnect or g==a.connecting or g==a.usable then self.desc.text=Tools.StrOfLocalization(2052)self.dot.text=''self:Hide()elseif g==a.closed then self.desc.text=Tools.StrOfLocalization(2049)self.dot.text=''elseif g==a.reconnecting then self.desc.text=Tools.StrOfLocalization(2050)self.dot.text=d end else if UI_Recharge and UI_Recharge.Inst.transform and UI_Recharge.Inst.transform.gameObject.activeSelf then UIMgr.Inst:ShowUI(UI_Recharge.className,nil,{index=UI_Recharge.Inst.page})end;self:Hide()end else self.desc.text=Tools.StrOfLocalization(2051)self.dot.text=''end;Tools.ReAlignPopoutText(self.desc)end;function UI_Disconnect:Hide()if self.locking then return end;if self.showState==b.gotoClose or self.showState==b.closed then return end;if self.showState==b.gotoClose then self.timerMgr:ClearAllTimers()self.showState=b.closed;return end;self:CloseSelf()end;function UI_Disconnect:Btn_Restart()GameMgr.Inst:ResetGame()end;return UI_Disconnect